 1	import * as React from 'react';
 2	import { ApplicationType, DRActionType } from '@odf/mco/constants';
 3	import { useApplicationFromPAV } from '@odf/mco/hooks/use-application-pav';
 4	import { ArgoApplicationSetKind } from '@odf/mco/types';
 5	import { ProtectedApplicationViewKind } from '@odf/mco/types/pav';
 6	import { ApplicationKind, useCustomTranslation } from '@odf/shared';
 7	import { CommonModalProps } from '@odf/shared/modals';
 8	import {
 9	  Modal,
10	  ModalVariant,
11	  Bullseye,
12	  Spinner,
13	  Alert,
14	} from '@patternfly/react-core';
15	import { ArogoApplicationSetParser } from '../app-failover-relocate/parser/argo-application-set-parser';
16	import { SubscriptionFailoverRelocateModal } from '../app-failover-relocate/subscriptions/failover-relocate-modal';
17	
18	type ApplicationActionModalProps = {
19	  pav: ProtectedApplicationViewKind;
20	  action: DRActionType.FAILOVER | DRActionType.RELOCATE;
21	};
22	
23	export const ApplicationActionModal: React.FC<
24	  CommonModalProps<ApplicationActionModalProps>
25	> = ({ isOpen, closeModal, extraProps: { pav, action } }) => {
26	  const { application, loaded, error, appInfo } = useApplicationFromPAV(pav);
27	  const { t } = useCustomTranslation();
28	
29	  if (!loaded || error || !application) {
30	    return (
31	      <Modal
32	        variant={ModalVariant.small}
33	        isOpen={isOpen}
34	        onClose={closeModal}
35	        title={action}
36	      >
37	        {!loaded ? (
38	          <Bullseye>
39	            <Spinner size="lg" />
40	          </Bullseye>
41	        ) : (
42	          <Alert variant="danger" title={t('Failed to fetch application')}>
43	            {error?.message}
44	          </Alert>
45	        )}
46	      </Modal>
47	    );
48	  }
49	
50	  return appInfo?.type === ApplicationType.ApplicationSet ? (
51	    <ArogoApplicationSetParser
52	      action={action}
53	      application={application as ArgoApplicationSetKind}
54	      isOpen={isOpen}
55	      close={closeModal}
56	    />
57	  ) : (
58	    <SubscriptionFailoverRelocateModal
59	      action={action}
60	      resource={application as ApplicationKind}
61	      isOpen={isOpen}
62	      close={closeModal}
63	    />
64	  );
65	};

